import os
import sys
import json
import traceback
import requests


def emit(obj):
    print(json.dumps(obj, ensure_ascii=False))


def get_env(name, default=None):
    return os.environ.get(name, default)


def validate_inputs():
    base_url = get_env('AUTH_BASEURL', '').strip()
    email = get_env('AUTH_EMAIL', '').strip()
    api_token = get_env('AUTH_APITOKEN', '').strip()

    assignee_account_id = get_env('CONFIG_ASSIGNEEACCOUNTID', '').strip()
    max_results_str = get_env('CONFIG_MAXRESULTSPERPAGE', '').strip()
    dry_run_str = get_env('CONFIG_DRYRUN', '').strip().lower()

    errors = []

    if not base_url:
        errors.append('Missing auth.baseUrl (e.g., https://your-domain.atlassian.net)')
    if not email:
        errors.append('Missing auth.email (Jira account email)')
    if not api_token:
        errors.append('Missing auth.apiToken (Jira API token)')
    if not assignee_account_id:
        errors.append('Missing configuration.assigneeAccountId (Jira user accountId)')

    # Parse maxResultsPerPage
    max_results = 50
    if max_results_str:
        try:
            max_results = int(max_results_str)
        except Exception:
            errors.append('configuration.maxResultsPerPage must be an integer')
    else:
        try:
            max_results = int(get_env('CONFIG_MAXRESULTSPERPAGE', '50'))
        except Exception:
            max_results = 50

    # Enforce sensible bounds (Jira typically allows up to 100 per request)
    if max_results < 1:
        max_results = 1
    if max_results > 100:
        max_results = 100

    dry_run = dry_run_str in ('1', 'true', 'yes', 'y', 'on') or (get_env('CONFIG_DRYRUN') is False)
    if dry_run_str == '' and isinstance(get_env('CONFIG_DRYRUN'), bool):
        dry_run = bool(get_env('CONFIG_DRYRUN'))

    return {
        'errors': errors,
        'base_url': base_url.rstrip('/'),
        'email': email,
        'api_token': api_token,
        'assignee_account_id': assignee_account_id,
        'max_results': max_results,
        'dry_run': dry_run
    }


def build_jql(assignee_account_id):
    # Quote the accountId to be safe in JQL
    return f'assignee = "{assignee_account_id}" ORDER BY created DESC'


def main():
    try:
        ctx = validate_inputs()
        if ctx['errors']:
            emit({
                'status': 'error',
                'error': 'validation_error',
                'messages': ctx['errors']
            })
            sys.exit(1)

        base_url = ctx['base_url']
        email = ctx['email']
        api_token = ctx['api_token']
        assignee_account_id = ctx['assignee_account_id']
        max_results = ctx['max_results']
        dry_run = ctx['dry_run']

        jql = build_jql(assignee_account_id)
        url = f"{base_url}/rest/api/3/search/jql"
        headers = {
            'Accept': 'application/json',
            'Content-Type': 'application/json'
        }

        if dry_run:
            body = {
                'jql': jql,
                'startAt': 0,
                'maxResults': max_results,
                'fields': [
                    'summary', 'status', 'assignee', 'project', 'issuetype', 'priority', 'created', 'updated'
                ]
            }
            emit({
                'status': 'dry_run',
                'request': {
                    'method': 'POST',
                    'url': url,
                    'headers': {k: v for k, v in headers.items()},
                    'body': body
                }
            })
            return

        all_issues = []
        start_at = 0
        total = None

        while True:
            body = {
                'jql': jql,
                'startAt': start_at,
                'maxResults': max_results,
                'fields': [
                    'summary', 'status', 'assignee', 'project', 'issuetype', 'priority', 'created', 'updated'
                ]
            }

            try:
                resp = requests.post(url, headers=headers, json=body, auth=(email, api_token), timeout=30)
            except requests.exceptions.RequestException as e:
                emit({
                    'status': 'error',
                    'error': 'request_failed',
                    'message': str(e),
                    'exception_type': type(e).__name__
                })
                sys.exit(1)

            if resp.status_code == 401:
                emit({
                    'status': 'error',
                    'error': 'unauthorized',
                    'message': 'Unauthorized. Check email and API token.'
                })
                sys.exit(1)
            if resp.status_code == 404:
                emit({
                    'status': 'error',
                    'error': 'not_found',
                    'message': 'Endpoint /rest/api/3/search/jql not found on this Jira instance. Ensure your Jira Cloud supports this endpoint.'
                })
                sys.exit(1)
            if resp.status_code == 429:
                emit({
                    'status': 'error',
                    'error': 'rate_limited',
                    'message': 'Rate limited by Jira API (HTTP 429). Please retry later.'
                })
                sys.exit(1)
            if resp.status_code >= 400:
                try:
                    err_json = resp.json()
                except Exception:
                    err_json = {'text': resp.text}
                emit({
                    'status': 'error',
                    'error': 'http_error',
                    'http_status': resp.status_code,
                    'response': err_json
                })
                sys.exit(1)

            try:
                data = resp.json()
            except ValueError:
                emit({
                    'status': 'error',
                    'error': 'invalid_response',
                    'message': 'Response was not valid JSON',
                    'http_status': resp.status_code,
                    'text': resp.text[:5000]
                })
                sys.exit(1)

            issues = data.get('issues', [])
            if total is None:
                total = data.get('total')

            for it in issues:
                key = it.get('key')
                fields = it.get('fields', {}) or {}
                summary = fields.get('summary')
                status_obj = fields.get('status') or {}
                status_name = None
                if isinstance(status_obj, dict):
                    status_name = status_obj.get('name')
                assignee_obj = fields.get('assignee') or {}
                assignee = None
                if isinstance(assignee_obj, dict):
                    assignee = {
                        'accountId': assignee_obj.get('accountId'),
                        'displayName': assignee_obj.get('displayName')
                    }
                project_obj = fields.get('project') or {}
                project_key = project_obj.get('key') if isinstance(project_obj, dict) else None
                issue_type_obj = fields.get('issuetype') or {}
                issue_type = issue_type_obj.get('name') if isinstance(issue_type_obj, dict) else None
                priority_obj = fields.get('priority') or {}
                priority = priority_obj.get('name') if isinstance(priority_obj, dict) else None
                created = fields.get('created')
                updated = fields.get('updated')

                all_issues.append({
                    'key': key,
                    'url': f"{base_url}/browse/{key}" if key else None,
                    'summary': summary,
                    'status': status_name,
                    'assignee': assignee,
                    'projectKey': project_key,
                    'issueType': issue_type,
                    'priority': priority,
                    'created': created,
                    'updated': updated
                })

            returned = len(issues)
            if returned == 0:
                break
            start_at += returned
            if total is not None and start_at >= total:
                break

        emit({
            'status': 'ok',
            'assigneeAccountId': assignee_account_id,
            'total': total if total is not None else len(all_issues),
            'fetched': len(all_issues),
            'issues': all_issues
        })

    except Exception as e:
        emit({
            'status': 'error',
            'error': 'unhandled_exception',
            'message': str(e),
            'exception_type': type(e).__name__,
            'traceback': traceback.format_exc()
        })
        sys.exit(1)


if __name__ == '__main__':
    main()
